Vue 相关（10题）

Vue 的响应式系统是其核心特性之一，让数据变化自动反映到视图上。

**Vue 2 响应式原理（Object.defineProperty）：**

```javascript
// 简化版实现
function defineReactive(obj, key, val) {
  const dep = new Dep(); // 依赖收集器

  Object.defineProperty(obj, key, {
    get() {
      if (Dep.target) {
        dep.depend(); // 收集依赖
      }
      return val;
    },
    set(newVal) {
      if (val !== newVal) {
        val = newVal;
        dep.notify(); // 通知更新
      }
    },
  });
}

// 依赖收集器
class Dep {
  constructor() {
    this.subs = []; // 订阅者列表
  }
  depend() {
    if (Dep.target) {
      this.subs.push(Dep.target);
    }
  }
  notify() {
    this.subs.forEach((watcher) => watcher.update());
  }
}

// Watcher 类
class Watcher {
  constructor(vm, exp, cb) {
    this.vm = vm;
    this.cb = cb;
    Dep.target = this;
    this.value = vm[exp]; // 触发 get，收集依赖
    Dep.target = null;
  }
  update() {
    const value = this.vm[this.exp];
    this.cb(value);
  }
}
```

**Vue 2 的问题：**

1. **无法检测新增/删除属性**

```javascript
this.obj.newProp = "value"; // 不响应
Vue.set(this.obj, "newProp", "value"); // 需要使用 Vue.set

delete this.obj.prop; // 不响应
Vue.delete(this.obj, "prop"); // 需要使用 Vue.delete
```

2. **数组变异方法需要重写**

```javascript
// Vue 重写了以下数组方法：
["push", "pop", "shift", "unshift", "splice", "sort", "reverse"];

// 直接通过索引修改不响应
this.arr[0] = "new"; // 不响应
this.arr.length = 0; // 不响应
```

3. **深层对象需要递归劫持，性能开销大**

**Vue 3 响应式原理（Proxy）：**

```javascript
// 简化版实现
function reactive(target) {
  return new Proxy(target, {
    get(target, key, receiver) {
      const result = Reflect.get(target, key, receiver);
      track(target, key); // 依赖收集
      // 递归代理
      if (result && typeof result === "object") {
        return reactive(result);
      }
      return result;
    },
    set(target, key, value, receiver) {
      const oldValue = target[key];
      const result = Reflect.set(target, key, value, receiver);
      if (oldValue !== value) {
        trigger(target, key); // 触发更新
      }
      return result;
    },
    deleteProperty(target, key) {
      const result = Reflect.deleteProperty(target, key);
      trigger(target, key);
      return result;
    },
    has(target, key) {
      track(target, key);
      return Reflect.has(target, key);
    },
  });
}

// 依赖收集（使用 WeakMap 存储）
const targetMap = new WeakMap();
let activeEffect = null;

function track(target, key) {
  if (!activeEffect) return;

  let depsMap = targetMap.get(target);
  if (!depsMap) {
    targetMap.set(target, (depsMap = new Map()));
  }

  let dep = depsMap.get(key);
  if (!dep) {
    depsMap.set(key, (dep = new Set()));
  }

  dep.add(activeEffect);
}

function trigger(target, key) {
  const depsMap = targetMap.get(target);
  if (!depsMap) return;

  const dep = depsMap.get(key);
  if (dep) {
    dep.forEach((effect) => effect());
  }
}

function effect(fn) {
  activeEffect = fn;
  fn();
  activeEffect = null;
}
```

**Vue 2 vs Vue 3 对比：**

| 特性         | Vue 2                 | Vue 3                  |
| ------------ | --------------------- | ---------------------- |
| **实现方式** | Object.defineProperty | Proxy                  |
| **新增属性** | 需 Vue.set            | 自动响应               |
| **删除属性** | 需 Vue.delete         | 自动响应               |
| **数组操作** | 重写 7 个方法         | 直接支持索引和 length  |
| **嵌套对象** | 初始化时递归劫持      | 懒代理（访问时才代理） |
| **Map/Set**  | 不支持                | 支持                   |
| **性能**     | 初始化慢              | 初始化快，代理开销小   |

**Vue 3 的响应式 API：**

```javascript
import { ref, reactive, computed, watch, watchEffect } from "vue";

// ref - 基本类型响应式
const count = ref(0);
console.log(count.value); // 访问值

// reactive - 对象响应式
const state = reactive({ name: "Tom", age: 25 });

// computed - 计算属性
const doubleCount = computed(() => count.value * 2);

// watch - 监听变化
watch(count, (newVal, oldVal) => {
  console.log("count changed:", newVal);
});

// watchEffect - 立即执行并追踪依赖
watchEffect(() => {
  console.log(count.value); // 自动追踪 count
});
```

**ref vs reactive 的选择：**

```javascript
// ref 适用场景
const count = ref(0); // 基本类型
const isActive = ref(true);

// reactive 适用场景
const form = reactive({
  // 表单对象
  name: "",
  email: "",
});

// ref 也可以用于对象（内部会调用 reactive）
const user = ref({ name: "Tom" });
user.value.name = "Jerry"; // 响应式

// reactive 的局限性：解构会失去响应式
const { name, age } = state; // name 和 age 不再是响应式

// 解决方案：使用 toRefs
import { toRefs } from "vue";
const { name, age } = toRefs(state); // 保持响应式
```

Vue 组件生命周期提供了在组件不同阶段执行代码的钩子函数。

**Vue 2 生命周期：**

```
创建阶段            挂载阶段             更新阶段            销毁阶段
   │                  │                   │                  │
   ▼                  ▼                   ▼                  ▼
beforeCreate    beforeMount         beforeUpdate       beforeDestroy
   │                  │                   │                  │
created ─────────► mounted ──────────► updated ─────────► destroyed

activated (keep-alive)
deactivated (keep-alive)
errorCaptured
```

**Vue 3 生命周期（Options API）：**

```
创建阶段            挂载阶段             更新阶段            卸载阶段
   │                  │                   │                  │
   ▼                  ▼                   ▼                  ▼
beforeCreate    beforeMount         beforeUpdate       beforeUnmount
   │                  │                   │                  │
created ─────────► mounted ──────────► updated ─────────► unmounted
```

**Vue 3 生命周期（Composition API）：**

```javascript
import {
  onBeforeMount,
  onMounted,
  onBeforeUpdate,
  onUpdated,
  onBeforeUnmount,
  onUnmounted,
  onErrorCaptured,
  onActivated,
  onDeactivated,
} from "vue";

export default {
  setup() {
    // setup 相当于 beforeCreate 和 created
    console.log("setup");

    onBeforeMount(() => console.log("onBeforeMount"));
    onMounted(() => console.log("onMounted"));
    onBeforeUpdate(() => console.log("onBeforeUpdate"));
    onUpdated(() => console.log("onUpdated"));
    onBeforeUnmount(() => console.log("onBeforeUnmount"));
    onUnmounted(() => console.log("onUnmounted"));

    return {};
  },
};
```

**各生命周期详解：**

| 阶段       | Vue 2         | Vue 3         | 说明                       |
| ---------- | ------------- | ------------- | -------------------------- |
| **创建前** | beforeCreate  | beforeCreate  | 实例初始化，未设置响应式   |
| **创建后** | created       | created       | 响应式已设置，可访问数据   |
| **挂载前** | beforeMount   | beforeMount   | 模板编译完成，未挂载到 DOM |
| **挂载后** | mounted       | mounted       | DOM 已挂载，可操作 DOM     |
| **更新前** | beforeUpdate  | beforeUpdate  | 数据已变，DOM 未更新       |
| **更新后** | updated       | updated       | DOM 已更新                 |
| **销毁前** | beforeDestroy | beforeUnmount | 实例仍可用                 |
| **销毁后** | destroyed     | unmounted     | 实例已销毁                 |

**created vs mounted 的区别：**

```javascript
export default {
  data() {
    return {
      message: "Hello",
    };
  },

  created() {
    // 实例已创建完成
    console.log(this.message); // 'Hello' - 可以访问数据

    // DOM 尚未挂载
    console.log(this.$el); // undefined
    console.log(document.getElementById("app")); // null

    // 适用场景：
    // 1. 数据初始化
    this.fetchData();
    // 2. 事件总线订阅
    EventBus.$on("event", this.handleEvent);
    // 3. 不涉及 DOM 的操作
  },

  mounted() {
    // DOM 已挂载
    console.log(this.$el); // <div>...</div>

    // 可以操作 DOM
    const height = this.$refs.container.offsetHeight;

    // 适用场景：
    // 1. DOM 操作
    // 2. 第三方库初始化（图表、富文本等）
    this.initChart();
    // 3. 需要 DOM 尺寸的计算
  },
};
```

**created vs mounted 的选择：**

| 场景           | 推荐                      |
| -------------- | ------------------------- |
| 数据请求       | created（更快，SSR 友好） |
| 事件订阅       | created                   |
| DOM 操作       | mounted                   |
| 第三方库初始化 | mounted                   |
| 计算 DOM 尺寸  | mounted                   |

**销毁阶段的清理工作：**

```javascript
export default {
  data() {
    return {
      timer: null,
      subscription: null,
      chart: null,
    };
  },

  created() {
    // 定时器
    this.timer = setInterval(() => {
      this.fetchData();
    }, 5000);

    // 事件订阅
    this.subscription = eventBus.subscribe("event", this.handleEvent);

    // DOM 事件
    window.addEventListener("resize", this.handleResize);
  },

  mounted() {
    // 初始化图表
    this.chart = echarts.init(this.$refs.chart);
  },

  // Vue 2
  beforeDestroy() {
    this.cleanup();
  },

  // Vue 3
  beforeUnmount() {
    this.cleanup();
  },

  methods: {
    cleanup() {
      // 1. 清除定时器
      if (this.timer) {
        clearInterval(this.timer);
        this.timer = null;
      }

      // 2. 取消事件订阅
      if (this.subscription) {
        this.subscription.unsubscribe();
        this.subscription = null;
      }

      // 3. 移除 DOM 事件监听
      window.removeEventListener("resize", this.handleResize);

      // 4. 销毁第三方实例
      if (this.chart) {
        this.chart.dispose();
        this.chart = null;
      }

      // 5. 取消未完成的请求（如果使用 axios）
      if (this.cancelToken) {
        this.cancelToken.cancel("Component unmounted");
      }
    },
  },
};
```

**Composition API 中的清理：**

```javascript
import { onMounted, onUnmounted } from "vue";

export default {
  setup() {
    let timer = null;
    let chart = null;

    onMounted(() => {
      timer = setInterval(() => {}, 1000);
      chart = echarts.init(chartRef.value);

      window.addEventListener("resize", handleResize);
    });

    onUnmounted(() => {
      if (timer) clearInterval(timer);
      if (chart) chart.dispose();
      window.removeEventListener("resize", handleResize);
    });

    return {};
  },
};
```

**keep-alive 的生命周期：**

```javascript
export default {
  activated() {
    // 组件被 keep-alive 缓存后，重新激活时调用
    console.log("组件激活");
  },

  deactivated() {
    // 组件被 keep-alive 缓存后，停用时调用
    console.log("组件停用");
  },
};

// 使用场景：
// - 滚动位置恢复
// - 重新请求数据
// - 暂停/恢复定时器
```

**错误处理生命周期：**

```javascript
export default {
  errorCaptured(err, vm, info) {
    // 捕获子组件错误
    console.error("Error:", err);
    console.log("Component:", vm);
    console.log("Info:", info);

    // 返回 false 阻止错误向上传播
    return false;
  },
};
```

Vue 指令是以 `v-` 开头的特殊属性，用于在表达式的值改变时，将某些行为应用到 DOM 上。

**内置指令分类：**

| 类别         | 指令                                   | 说明          |
| ------------ | -------------------------------------- | ------------- |
| **渲染**     | v-if, v-else, v-else-if, v-show, v-for | 条件/列表渲染 |
| **数据绑定** | v-bind, v-model, v-text, v-html        | 数据绑定      |
| **事件**     | v-on                                   | 事件监听      |
| **属性**     | v-pre, v-cloak, v-once                 | 特殊属性      |
| **自定义**   | v-directive                            | 自定义指令    |

**v-bind 详解：**

```html
<!-- 完整语法 -->
<a v-bind:href="url">Link</a>

<!-- 缩写 -->
<a :href="url">Link</a>

<!-- 绑定对象 -->
<div :class="{ active: isActive, 'text-danger': hasError }"></div>

<!-- 绑定数组 -->
<div :class="[activeClass, errorClass]"></div>

<!-- 绑定样式 -->
<div :style="{ color: activeColor, fontSize: fontSize + 'px' }"></div>

<!-- 绑定对象 -->
<div v-bind="{ id: 'app', class: 'container' }"></div>
```

**v-on 详解：**

```html
<!-- 完整语法 -->
<button v-on:click="handleClick">Click</button>

<!-- 缩写 -->
<button @click="handleClick">Click</button>

<!-- 内联语句 -->
<button @click="count++">Add</button>

<!-- 访问事件对象 -->
<button @click="handleClick($event)">Click</button>

<!-- 事件修饰符 -->
<form @submit.prevent="onSubmit"></form>
<!-- 阻止默认行为 -->
<div @click.stop="doThis"></div>
<!-- 阻止冒泡 -->
<div @click.capture="doThis"></div>
<!-- 捕获模式 -->
<div @click.self="doThis"></div>
<!-- 只触发自己 -->
<div @click.once="doThis"></div>
<!-- 只触发一次 -->
<div @scroll.passive="onScroll"></div>
<!--  passive 模式 -->

<!-- 按键修饰符 -->
<input @keyup.enter="submit" />
<input @keyup.esc="cancel" />
<input @keyup.ctrl.c="copy" />

<!-- 系统修饰符 -->
<div @click.ctrl="onCtrlClick">Ctrl + Click</div>
```

**v-if vs v-show 详解：**

| 特性              | v-if                | v-show                     |
| ----------------- | ------------------- | -------------------------- |
| **渲染方式**      | 条件为假时不渲染    | 始终渲染，只是切换 display |
| **切换开销**      | 高（创建/销毁组件） | 低（仅切换 CSS）           |
| **初始渲染**      | 条件为假时不渲染    | 始终渲染                   |
| **适用场景**      | 切换不频繁          | 频繁切换                   |
| **支持 template** | 支持                | 不支持                     |
| **v-else**        | 支持                | 不支持                     |

```html
<!-- v-if - 条件渲染 -->
<div v-if="type === 'A'">A</div>
<div v-else-if="type === 'B'">B</div>
<div v-else>Other</div>

<!-- v-show - 显示/隐藏 -->
<div v-show="isVisible">Content</div>
<!-- 相当于：
<div style="display: none;">Content</div>
-->
```

**v-if 的原理：**

```javascript
// 编译后的渲染函数大致如下
function render() {
  return this.type === "A"
    ? h("div", "A")
    : this.type === "B"
      ? h("div", "B")
      : h("div", "Other");
}

// 切换时，Vue 会销毁/创建组件
// 可以使用 <template> 包装多个元素
<template v-if="ok">
  <h1>Title</h1>
  <p>Paragraph</p>
</template>;
```

**v-show 的原理：**

```javascript
// 编译后添加 display 样式
function render() {
  return h(
    "div",
    {
      style: { display: this.isVisible ? "" : "none" },
    },
    "Content",
  );
}
```

**v-model 详解：**

```html
<!-- 文本输入 -->
<input v-model="message" />
<!-- 相当于：
<input :value="message" @input="message = $event.target.value">
-->

<!-- 多行文本 -->
<textarea v-model="message"></textarea>

<!-- 复选框 -->
<input type="checkbox" v-model="checked" />

<!-- 多个复选框 -->
<input type="checkbox" v-model="checkedNames" value="Jack" />
<input type="checkbox" v-model="checkedNames" value="John" />

<!-- 单选按钮 -->
<input type="radio" v-model="picked" value="One" />
<input type="radio" v-model="picked" value="Two" />

<!-- 选择器 -->
<select v-model="selected">
  <option disabled value="">请选择</option>
  <option>A</option>
  <option>B</option>
</select>

<!-- 修饰符 -->
<input v-model.lazy="msg" />
<!-- 懒更新（change 事件） -->
<input v-model.number="age" />
<!-- 转为数字 -->
<input v-model.trim="msg" />
<!-- 去除首尾空格 -->
```

**v-model 原理：**

```javascript
// Vue 2
const Vue = {
  model: {
    prop: 'value',
    event: 'input'
  },
  props: ['value'],
  template: `
    <input
      :value="value"
      @input="$emit('input', $event.target.value)"
    >
  `
};

// Vue 3
const MyInput = {
  props: ['modelValue'],
  emits: ['update:modelValue'],
  template: `
    <input
      :value="modelValue"
      @input="$emit('update:modelValue', $event.target.value)"
    >
  `
};

// 使用
<MyInput v-model="message" />
<!-- 相当于：
<MyInput
  :modelValue="message"
  @update:modelValue="message = $event"
/>
-->

// 自定义 v-model 名称
<MyInput v-model:title="pageTitle" />
```

**自定义指令：**

```javascript
// Vue 2
Vue.directive('focus', {
  inserted(el) {
    el.focus();
  }
});

// Vue 3
const vFocus = {
  mounted(el) {
    el.focus();
  }
};

// 使用
<input v-focus>

// 完整钩子（Vue 3）
const myDirective = {
  // 在绑定元素的 attribute 前或事件监听器应用前调用
  created(el, binding, vnode, prevVnode) {},
  // 在元素被插入到 DOM 前调用
  beforeMount(el, binding, vnode, prevVnode) {},
  // 在绑定元素的父组件及它自己的所有子节点都挂载完成后调用
  mounted(el, binding, vnode, prevVnode) {},
  // 绑定元素的父组件更新前调用
  beforeUpdate(el, binding, vnode, prevVnode) {},
  // 在绑定元素的父组件及它自己的所有子节点都更新后调用
  updated(el, binding, vnode, prevVnode) {},
  // 绑定元素的父组件卸载前调用
  beforeUnmount(el, binding, vnode, prevVnode) {},
  // 绑定元素的父组件卸载后调用
  unmounted(el, binding, vnode, prevVnode) {}
};
```

**常用自定义指令示例：**

```javascript
// 点击外部关闭（用于下拉菜单、弹窗等）
const vClickOutside = {
  mounted(el, binding) {
    el._clickOutside = (event) => {
      if (!(el === event.target || el.contains(event.target))) {
        binding.value();
      }
    };
    document.addEventListener('click', el._clickOutside);
  },
  unmounted(el) {
    document.removeEventListener('click', el._clickOutside);
  }
};

// 使用
<div v-click-outside="closeDropdown">
  <!-- 下拉内容 -->
</div>

// 防抖指令
const vDebounce = {
  mounted(el, binding) {
    let timer;
    el._debounce = () => {
      clearTimeout(timer);
      timer = setTimeout(() => {
        binding.value();
      }, 300);
    };
    el.addEventListener('input', el._debounce);
  },
  unmounted(el) {
    el.removeEventListener('input', el._debounce);
  }
};

// 使用
<input v-debounce="search">
```

Vue 提供了多种组件通信方式，适用于不同的场景和组件关系。

**1. Props / $emit（父子通信）**

```vue
<!-- Parent.vue -->
<template>
  <Child
    :title="pageTitle"
    :user="currentUser"
    @update="handleUpdate"
    @delete="handleDelete"
  />
</template>

<!-- Child.vue -->
<template>
  <div>
    <h1>{{ title }}</h1>
    <p>{{ user.name }}</p>
    <button @click="$emit('update', data)">更新</button>
    <button @click="$emit('delete', id)">删除</button>
  </div>
</template>

<script>
export default {
  props: {
    title: {
      type: String,
      required: true,
      default: "Default Title",
    },
    user: {
      type: Object,
      default: () => ({}),
    },
  },
  emits: ["update", "delete"],
};
</script>
```

**2. $refs / $parent（直接访问）**

```vue
<!-- 父组件调用子组件方法 -->
<template>
  <Child ref="childRef" />
  <button @click="callChildMethod">调用子组件</button>
</template>

<script>
export default {
  methods: {
    callChildMethod() {
      this.$refs.childRef.childMethod();
      console.log(this.$refs.childRef.childData);
    },
  },
};
</script>

<!-- 子组件访问父组件 -->
<script>
export default {
  mounted() {
    console.log(this.$parent.parentData);
  },
};
</script>
```

**3. Event Bus（全局事件，Vue 3 不推荐）**

```javascript
// Vue 2
// eventBus.js
import Vue from "vue";
export const eventBus = new Vue();

// 发送
eventBus.$emit("user:login", userData);

// 接收
eventBus.$on("user:login", (data) => {
  console.log(data);
});

// Vue 3 - 使用 mitt 库替代
import mitt from "mitt";
export const emitter = mitt();

// 发送
emitter.emit("user:login", userData);

// 接收
emitter.on("user:login", (data) => {});
```

**4. Provide / Inject（跨层级通信）**

```vue
<!-- 祖先组件 -->
<script>
import { provide, ref } from "vue";

export default {
  setup() {
    const user = ref({ name: "Tom" });
    const updateUser = (newUser) => {
      user.value = newUser;
    };

    provide("user", user);
    provide("updateUser", updateUser);

    return {};
  },
};
</script>

<!-- 深层子组件 -->
<script>
import { inject } from "vue";

export default {
  setup() {
    const user = inject("user");
    const updateUser = inject("updateUser");

    return { user, updateUser };
  },
};
</script>
```

**5. Vuex / Pinia（全局状态管理）**

```javascript
// Pinia (Vue 3 推荐)
// stores/counter.js
import { defineStore } from 'pinia';

export const useCounterStore = defineStore('counter', {
  state: () => ({
    count: 0,
    name: 'Counter'
  }),
  getters: {
    doubleCount: (state) => state.count * 2
  },
  actions: {
    increment() {
      this.count++;
    }
  }
});

// 组件中使用
<script setup>
import { useCounterStore } from '@/stores/counter';

const counter = useCounterStore();
</script>

<template>
  <div>
    <p>{{ counter.count }}</p>
    <p>{{ counter.doubleCount }}</p>
    <button @click="counter.increment">+</button>
  </div>
</template>
```

**6. Slots（内容分发）**

```vue
<!-- 子组件：BaseLayout.vue -->
<template>
  <header>
    <slot name="header">默认头部</slot>
  </header>
  <main>
    <slot>默认内容</slot>
  </main>
  <footer>
    <slot name="footer"></slot>
  </footer>
</template>

<!-- 父组件使用 -->
<BaseLayout>
  <template #header>
    <h1>自定义头部</h1>
  </template>

  <p>主要内容</p>

  <template #footer>
    <p>自定义底部</p>
  </template>
</BaseLayout>

<!-- 作用域插槽 -->
<!-- 子组件 -->
<slot :user="user" :posts="posts"></slot>

<!-- 父组件 -->
<Child v-slot="{ user, posts }">
  <p>{{ user.name }}</p>
  <ul>
    <li v-for="post in posts" :key="post.id">{{ post.title }}</li>
  </ul>
</Child>
```

**7. $attrs / $listeners（属性透传）**

```vue
<!-- InputWrapper.vue - 封装组件 -->
<template>
  <label>
    {{ label }}
    <input v-bind="$attrs" v-on="$listeners" />
  </label>
</template>

<script>
export default {
  inheritAttrs: false, // 禁用自动继承
  props: ["label"],
};
</script>

<!-- 使用 -->
<InputWrapper
  label="用户名"
  type="text"
  placeholder="请输入"
  @focus="onFocus"
  @blur="onBlur"
/>
```

**Vue 3 的透传属性（Attributes）：**

```vue
<!-- MyButton.vue -->
<template>
  <button class="btn">Click</button>
</template>

<!-- 父组件 -->
<MyButton class="large" id="submit" />

<!-- 渲染结果（class 会合并） -->
<button class="btn large" id="submit">Click</button>
```

**通信方式选择指南：**

| 场景         | 推荐方案         | 说明               |
| ------------ | ---------------- | ------------------ |
| 父子通信     | Props / $emit    | 最直接，单向数据流 |
| 深层嵌套     | Provide / Inject | 避免逐层传递 props |
| 全局共享状态 | Pinia / Vuex     | 应用级状态管理     |
| 表单组件     | v-model          | 双向绑定语法糖     |
| 内容分发     | Slots            | 灵活的内容插入     |
| 命令式操作   | $refs            | 直接调用组件方法   |
| 全局事件     | mitt / Event Bus | 解耦但难以追踪     |

**Pinia vs Vuex 对比：**

| 特性           | Vuex 4             | Pinia                 |
| -------------- | ------------------ | --------------------- |
| **语法**       | 选项式 API         | 选项式/组合式 API     |
| **TypeScript** | 需要额外配置       | 天生支持              |
| **体积**       | 较大               | 轻量（~1KB）          |
| **API**        | mutations, actions | 只有 actions          |
| **开发体验**   | 一般               | 更好（Devtools 支持） |
| **模块化**     | 需要命名空间       | 自动模块化            |
| **Vue 3 推荐** | 支持               | ⭐⭐⭐ 官方推荐       |

**实际项目建议：**

```javascript
// 1. 优先使用 Props / Events
// 2. 深层传递用 Provide / Inject
// 3. 全局状态用 Pinia
// 4. 避免滥用 Event Bus（难以调试）
// 5. 合理使用 Slots 提高组件复用性
```

Vuex 和 Pinia 都是 Vue 的状态管理库，用于集中管理应用的状态。

**核心作用：**

1. **集中式状态管理**：所有组件共享一个状态树
2. **可预测的状态变更**：通过 mutations/actions 修改状态
3. **开发工具支持**：时间旅行、状态快照
4. **模块化管理**：将状态拆分为多个模块

**Vuex 详解：**

```javascript
// store/index.js
import { createStore } from "vuex";

export default createStore({
  // 状态
  state: {
    count: 0,
    user: null,
    todos: [],
  },

  // 计算属性
  getters: {
    doubleCount: (state) => state.count * 2,
    isLoggedIn: (state) => !!state.user,
    getTodoById: (state) => (id) => {
      return state.todos.find((todo) => todo.id === id);
    },
  },

  // 同步修改（唯一可以修改 state 的地方）
  mutations: {
    INCREMENT(state) {
      state.count++;
    },
    SET_USER(state, user) {
      state.user = user;
    },
    ADD_TODO(state, todo) {
      state.todos.push(todo);
    },
  },

  // 异步操作
  actions: {
    async fetchUser({ commit }, userId) {
      commit("SET_LOADING", true);
      try {
        const user = await api.getUser(userId);
        commit("SET_USER", user);
      } catch (error) {
        commit("SET_ERROR", error.message);
      }
    },
    incrementAsync({ commit }, delay) {
      setTimeout(() => {
        commit("INCREMENT");
      }, delay);
    },
  },

  // 模块
  modules: {
    cart: cartModule,
    products: productsModule,
  },
});
```

**Pinia 详解：**

```javascript
// stores/counter.js
import { defineStore } from 'pinia';

// Options API 风格
export const useCounterStore = defineStore('counter', {
  state: () => ({
    count: 0,
    name: 'Counter'
  }),
  getters: {
    doubleCount: (state) => state.count * 2,
    doublePlusOne(): number {
      return this.doubleCount + 1;
    }
  },
  actions: {
    increment() {
      this.count++;
    },
    async fetchCount() {
      const response = await fetch('/api/count');
      this.count = await response.json();
    }
  }
});

// Composition API 风格（推荐）
import { ref, computed } from 'vue';

export const useCounterStore = defineStore('counter', () => {
  // state
  const count = ref(0);
  const name = ref('Counter');

  // getters
  const doubleCount = computed(() => count.value * 2);

  // actions
  function increment() {
    count.value++;
  }

  async function fetchCount() {
    const response = await fetch('/api/count');
    count.value = await response.json();
  }

  return { count, name, doubleCount, increment, fetchCount };
});
```

**Vuex vs Pinia 对比：**

| 特性           | Vuex 4                 | Pinia                  |
| -------------- | ---------------------- | ---------------------- |
| **语法**       | 选项式，必须 mutations | 更灵活，直接修改 state |
| **TypeScript** | 需要类型声明           | 天生完美支持           |
| **代码量**     | 较多                   | 更少                   |
| **Devtools**   | 支持                   | 更好支持               |
| **服务端渲染** | 需要额外配置           | 内置支持               |
| **模块化**     | 命名空间复杂           | 自动模块化             |
| **体积**       | ~1.5KB                 | ~1KB                   |
| **学习曲线**   | 较高                   | 较低                   |
| **Vue 3 推荐** | 支持                   | ⭐ 官方推荐            |

**Vuex 状态树设计：**

```javascript
// 推荐的分层结构
store/
├── index.js          # 入口，组装模块
├── modules/
│   ├── user.js       # 用户模块
│   ├── cart.js       # 购物车模块
│   ├── products.js   # 商品模块
│   └── orders.js     # 订单模块
├── getters.js        # 全局 getters
└── actions.js        # 全局 actions

// store/modules/user.js
const state = {
  token: localStorage.getItem('token'),
  info: null,
  permissions: []
};

const getters = {
  isLoggedIn: state => !!state.token,
  username: state => state.info?.name
};

const mutations = {
  SET_TOKEN(state, token) {
    state.token = token;
    localStorage.setItem('token', token);
  },
  SET_USER_INFO(state, info) {
    state.info = info;
  },
  CLEAR_USER(state) {
    state.token = null;
    state.info = null;
    state.permissions = [];
    localStorage.removeItem('token');
  }
};

const actions = {
  async login({ commit }, credentials) {
    const { token, user } = await api.login(credentials);
    commit('SET_TOKEN', token);
    commit('SET_USER_INFO', user);
    return user;
  },

  async logout({ commit }) {
    await api.logout();
    commit('CLEAR_USER');
  },

  async fetchUserInfo({ commit }) {
    const user = await api.getUserInfo();
    commit('SET_USER_INFO', user);
  }
};

export default {
  namespaced: true,  // 开启命名空间
  state,
  getters,
  mutations,
  actions
};

// store/index.js
import { createStore } from 'vuex';
import user from './modules/user';
import cart from './modules/cart';

export default createStore({
  modules: {
    user,
    cart
  }
});

// 组件中使用
export default {
  computed: {
    ...mapState('user', ['info']),
    ...mapGetters('user', ['isLoggedIn'])
  },
  methods: {
    ...mapActions('user', ['login', 'logout'])
  }
}
```

**状态设计原则：**

```javascript
// 1. 单一数据源
const state = {
  users: [],           // 原始数据
  currentUserId: null, // 当前选中
  loading: false,      // 加载状态
  error: null          // 错误信息
};

// 2. 派生状态用 getters
getters: {
  currentUser: state => {
    return state.users.find(u => u.id === state.currentUserId);
  },
  sortedUsers: state => {
    return [...state.users].sort((a, b) => b.score - a.score);
  }
}

// 3. 异步操作在 actions
actions: {
  async fetchUsers({ commit }) {
    commit('SET_LOADING', true);
    try {
      const users = await api.getUsers();
      commit('SET_USERS', users);
    } catch (error) {
      commit('SET_ERROR', error.message);
    } finally {
      commit('SET_LOADING', false);
    }
  }
}

// 4. 模块划分原则
// - 按功能领域划分
// - 每个模块独立管理自己的状态
// - 跨模块通信通过 root state 或 dispatch 到其他模块
```

**Pinia 最佳实践：**

```javascript
// stores/user.js
import { defineStore } from 'pinia';
import { ref, computed } from 'vue';

export const useUserStore = defineStore('user', () => {
  // State
  const token = ref(localStorage.getItem('token'));
  const userInfo = ref(null);
  const loading = ref(false);

  // Getters
  const isLoggedIn = computed(() => !!token.value);
  const displayName = computed(() => userInfo.value?.name || 'Guest');

  // Actions
  async function login(credentials) {
    loading.value = true;
    try {
      const { token: newToken, user } = await api.login(credentials);
      token.value = newToken;
      userInfo.value = user;
      localStorage.setItem('token', newToken);
      return user;
    } finally {
      loading.value = false;
    }
  }

  function logout() {
    token.value = null;
    userInfo.value = null;
    localStorage.removeItem('token');
  }

  return {
    token,
    userInfo,
    loading,
    isLoggedIn,
    displayName,
    login,
    logout
  };
});

// 组件中使用
<script setup>
import { useUserStore } from '@/stores/user';
import { storeToRefs } from 'pinia';

const userStore = useUserStore();

// 保持响应式解构
const { isLoggedIn, displayName } = storeToRefs(userStore);

// 方法可以直接解构
const { login, logout } = userStore;
</script>
```

**现代项目推荐：**

- Vue 3 新项目：使用 Pinia
- Vue 2 项目：继续使用 Vuex 或升级到 Pinia
- 需要 SSR：Pinia 支持更好

Vue Router 提供了多种路由守卫，用于在导航过程中进行权限验证、数据预取等操作。

**路由守卫分类：**

| 类型         | 守卫                                                  | 说明             |
| ------------ | ----------------------------------------------------- | ---------------- |
| **全局**     | beforeEach, beforeResolve, afterEach                  | 所有路由都会触发 |
| **路由独享** | beforeEnter                                           | 单个路由配置     |
| **组件内**   | beforeRouteEnter, beforeRouteUpdate, beforeRouteLeave | 组件内部定义     |

**全局守卫：**

```javascript
// router/index.js
import { createRouter, createWebHistory } from "vue-router";

const router = createRouter({
  history: createWebHistory(),
  routes,
});

// 1. 全局前置守卫 - 最常用
router.beforeEach((to, from, next) => {
  // to: 目标路由
  // from: 来源路由
  // next: 控制导航

  // 检查登录状态
  const isLoggedIn = localStorage.getItem("token");
  const requiresAuth = to.matched.some((record) => record.meta.requiresAuth);

  if (requiresAuth && !isLoggedIn) {
    next({
      path: "/login",
      query: { redirect: to.fullPath },
    });
  } else {
    next(); // 继续导航
  }
});

// 2. 全局解析守卫 - 在组件内守卫和异步路由之后
router.beforeResolve((to, from, next) => {
  // 可以在这里做全局数据预取
  next();
});

// 3. 全局后置钩子 - 没有 next，不能阻止导航
router.afterEach((to, from) => {
  // 设置页面标题
  document.title = to.meta.title || "默认标题";
  // 埋点上报
  analytics.trackPageView(to.fullPath);
});

// 错误处理
router.onError((error) => {
  console.error("路由错误:", error);
});
```

**路由独享守卫：**

```javascript
const routes = [
  {
    path: "/admin",
    component: Admin,
    meta: { requiresAdmin: true },
    beforeEnter: (to, from, next) => {
      // 单个路由的权限检查
      const isAdmin = store.state.user.role === "admin";
      if (isAdmin) {
        next();
      } else {
        next("/403");
      }
    },
  },
  {
    path: "/user/:id",
    component: User,
    // 可以定义多个守卫
    beforeEnter: [guard1, guard2],
  },
];
```

**组件内守卫：**

```javascript
export default {
  // 1. 进入组件前 - 不能访问 this
  beforeRouteEnter(to, from, next) {
    fetchUser(to.params.id).then((user) => {
      // 通过 next 传递数据给组件
      next((vm) => {
        vm.user = user;
      });
    });
  },

  // 2. 当前组件复用时（动态参数变化）
  beforeRouteUpdate(to, from, next) {
    // 可以访问 this
    this.user = null;
    fetchUser(to.params.id).then((user) => {
      this.user = user;
      next();
    });
  },

  // 3. 离开组件前 - 常用于确认提示
  beforeRouteLeave(to, from, next) {
    if (this.hasUnsavedChanges) {
      const answer = window.confirm("您有未保存的更改，确定离开吗？");
      if (answer) {
        next();
      } else {
        next(false); // 取消导航
      }
    } else {
      next();
    }
  },
};
```

**Composition API 中的路由守卫：**

```vue
<script setup>
import { onBeforeRouteLeave, onBeforeRouteUpdate } from "vue-router";

// 离开守卫
onBeforeRouteLeave((to, from, next) => {
  const answer = window.confirm("确定离开吗？");
  next(answer);
});

// 更新守卫
onBeforeRouteUpdate((to, from, next) => {
  // 响应路由参数变化
  userId.value = to.params.id;
  fetchUserData();
  next();
});
</script>
```

**执行顺序：**

```
导航触发
    ↓
【1】全局 beforeEach
    ↓
【2】路由独享 beforeEnter（如果有重用的组件，跳过）
    ↓
【3】组件内 beforeRouteEnter（如果是复用组件，改为 beforeRouteUpdate）
    ↓
【4】全局 beforeResolve
    ↓
导航被确认
    ↓
【5】全局 afterEach
    ↓
DOM 更新
    ↓
触发组件内 beforeRouteEnter 的 next 回调（如果有）
```

**实际应用场景：**

```javascript
// 1. 登录验证
router.beforeEach((to, from, next) => {
  const token = localStorage.getItem('token');
  const publicPages = ['/login', '/register'];
  const authRequired = !publicPages.includes(to.path);

  if (authRequired && !token) {
    return next('/login');
  }

  if (to.path === '/login' && token) {
    return next('/');
  }

  next();
});

// 2. 权限控制
router.beforeEach((to, from, next) => {
  const { permissions } = store.state.user;
  const requiredPermissions = to.meta.permissions || [];

  const hasPermission = requiredPermissions.every(p =>
    permissions.includes(p)
  );

  if (requiredPermissions.length > 0 && !hasPermission) {
    return next('/403');
  }

  next();
});

// 3. 页面标题和元信息
router.afterEach((to) => {
  document.title = to.meta.title || 'My App';

  // 埋点
  gtag('config', 'GA_TRACKING_ID', {
    page_path: to.path
  });
});

// 4. 路由懒加载的 loading
let loadingInstance;
router.beforeEach(() => {
  loadingInstance = ElLoading.service();
});
router.afterEach(() => {
  loadingInstance.close();
});

// 5. 数据预取
{
  path: '/post/:id',
  component: Post,
  beforeEnter: async (to, from, next) => {
    try {
      const post = await fetchPost(to.params.id);
      to.meta.post = post; // 将数据附加到路由
      next();
    } catch (error) {
      next({ name: 'NotFound' });
    }
  }
}
```

**导航控制：**

```javascript
// next() - 确认导航
next(false); // 取消导航
next("/path"); // 跳转到指定路径
next({ name: "Home" }); // 使用命名路由
next(error); // 导航报错
```

Composition API 是 Vue 3 引入的一种新的组件编写方式，作为 Options API 的替代和补充。

**核心区别：**

| 特性           | Options API                           | Composition API    |
| -------------- | ------------------------------------- | ------------------ |
| **代码组织**   | 按选项类型（data, methods, computed） | 按功能逻辑组合     |
| **复用逻辑**   | Mixins, 高阶组件                      | Composable 函数    |
| **TypeScript** | 类型推断困难                          | 完整类型支持       |
| **代码量**     | 选项分散                              | 相关逻辑集中       |
| **学习曲线**   | 直观，易上手                          | 需要理解响应式原理 |

**Options API 示例：**

```javascript
export default {
  data() {
    return {
      // 搜索功能的状态分散在 data 中
      searchQuery: "",
      searchResults: [],
      loading: false,

      // 用户功能的状态
      user: null,
      isLoggedIn: false,
    };
  },

  computed: {
    // 搜索功能的计算属性
    filteredResults() {
      return this.searchResults.filter((r) =>
        r.title.includes(this.searchQuery),
      );
    },

    // 用户功能的计算属性
    displayName() {
      return this.user?.name || "Guest";
    },
  },

  methods: {
    // 搜索功能的方法
    async search() {
      this.loading = true;
      this.searchResults = await api.search(this.searchQuery);
      this.loading = false;
    },

    // 用户功能的方法
    async login(credentials) {
      this.user = await api.login(credentials);
      this.isLoggedIn = true;
    },
  },

  mounted() {
    // 初始化逻辑分散
    this.fetchInitialData();
    this.checkLoginStatus();
  },
};
```

**Composition API 示例：**

```javascript
import { ref, computed, onMounted } from "vue";

// 搜索功能抽离为 composable
function useSearch() {
  const searchQuery = ref("");
  const searchResults = ref([]);
  const loading = ref(false);

  const filteredResults = computed(() => {
    return searchResults.value.filter((r) =>
      r.title.includes(searchQuery.value),
    );
  });

  async function search() {
    loading.value = true;
    searchResults.value = await api.search(searchQuery.value);
    loading.value = false;
  }

  return {
    searchQuery,
    searchResults,
    loading,
    filteredResults,
    search,
  };
}

// 用户功能抽离为 composable
function useUser() {
  const user = ref(null);
  const isLoggedIn = computed(() => !!user.value);

  async function login(credentials) {
    user.value = await api.login(credentials);
  }

  function logout() {
    user.value = null;
  }

  return {
    user,
    isLoggedIn,
    login,
    logout,
  };
}

// 组件中使用
export default {
  setup() {
    // 组合多个功能逻辑
    const { searchQuery, searchResults, loading, filteredResults, search } =
      useSearch();

    const { user, isLoggedIn, login, logout } = useUser();

    onMounted(() => {
      // 初始化逻辑清晰
    });

    return {
      // 暴露给模板
      searchQuery,
      filteredResults,
      loading,
      search,
      user,
      isLoggedIn,
      login,
      logout,
    };
  },
};
```

**Composition API 的优势：**

**1. 更好的逻辑复用**

```javascript
// 鼠标位置追踪 composable
// composables/useMouse.js
import { ref, onMounted, onUnmounted } from "vue";

export function useMouse() {
  const x = ref(0);
  const y = ref(0);

  function update(event) {
    x.value = event.pageX;
    y.value = event.pageY;
  }

  onMounted(() => window.addEventListener("mousemove", update));
  onUnmounted(() => window.removeEventListener("mousemove", update));

  return { x, y };
}

// 任何组件都可以使用
import { useMouse } from "./composables/useMouse";

export default {
  setup() {
    const { x, y } = useMouse();
    return { x, y };
  },
};
```

**2. 更灵活的代码组织**

```vue
<script setup>
import { ref, computed } from "vue";

// ===== 搜索功能 =====
const searchQuery = ref("");
const results = ref([]);
const search = async () => {
  /* ... */
};

// ===== 分页功能 =====
const currentPage = ref(1);
const totalPages = computed(() => Math.ceil(results.value.length / 10));
const nextPage = () => currentPage.value++;

// ===== 排序功能 =====
const sortKey = ref("date");
const sortedResults = computed(() => {
  return [...results.value].sort((a, b) => {
    return a[sortKey.value] > b[sortKey.value] ? 1 : -1;
  });
});
</script>
```

**3. 完整的 TypeScript 支持**

```typescript
import { ref, computed } from "vue";

interface User {
  id: number;
  name: string;
  email: string;
}

export function useUser() {
  const user = ref<User | null>(null);
  const isLoggedIn = computed<boolean>(() => !!user.value);

  async function fetchUser(id: number): Promise<void> {
    const response = await fetch(`/api/users/${id}`);
    user.value = (await response.json()) as User;
  }

  return {
    user: readonly(user), // 导出只读引用
    isLoggedIn,
    fetchUser,
  };
}
```

**4. 更小的打包体积**

```javascript
// 只导入需要的 API
import { ref, computed } from "vue";
// 而不是导入整个 Vue

// Tree-shaking 友好
// 未使用的功能不会被打包
```

**使用场景建议：**

| 场景          | 推荐 API                       |
| ------------- | ------------------------------ |
| 简单组件      | Options API 或 Composition API |
| 复杂逻辑      | Composition API                |
| 需要类型安全  | Composition API                |
| 逻辑复用      | Composition API                |
| 从 Vue 2 迁移 | 渐进式采用 Composition API     |

**现代 Vue 3 推荐写法：**

```vue
<script setup>
// 最简洁的 Composition API 写法
import { ref, computed, watch, onMounted } from "vue";
import { useUser } from "@/composables/useUser";
import { useRoute } from "vue-router";

// 响应式数据
const count = ref(0);
const user = useUser();
const route = useRoute();

// 计算属性
const doubleCount = computed(() => count.value * 2);

// 方法
function increment() {
  count.value++;
}

// 监听
watch(count, (newVal) => {
  console.log("Count changed:", newVal);
});

// 生命周期
onMounted(() => {
  console.log("Component mounted");
});
</script>

<template>
  <div>
    <p>{{ count }} x 2 = {{ doubleCount }}</p>
    <button @click="increment">+</button>
  </div>
</template>
```

computed 和 watch 都是 Vue 中用于响应式处理的重要 API，但用途和使用方式不同。

**核心区别：**

| 特性             | computed                   | watch                        |
| ---------------- | -------------------------- | ---------------------------- |
| **用途**         | 计算派生值                 | 监听变化并执行副作用         |
| **返回值**       | 有，返回计算结果           | 无                           |
| **缓存**         | 有缓存，依赖不变不重新计算 | 无缓存，每次变化都执行       |
| **使用场景**     | 基于现有数据计算新值       | 数据变化时执行异步或复杂操作 |
| **是否支持异步** | 不支持                     | 支持                         |

**computed 详解：**

```javascript
// Options API
export default {
  data() {
    return {
      firstName: "Tom",
      lastName: "Jerry",
      items: [
        { name: "Apple", price: 10, quantity: 2 },
        { name: "Banana", price: 5, quantity: 3 },
      ],
    };
  },

  computed: {
    // 只读计算属性
    fullName() {
      return `${this.firstName} ${this.lastName}`;
    },

    // 可读可写计算属性
    fullName: {
      get() {
        return `${this.firstName} ${this.lastName}`;
      },
      set(newValue) {
        [this.firstName, this.lastName] = newValue.split(" ");
      },
    },

    // 复杂计算
    totalPrice() {
      return this.items.reduce((sum, item) => {
        return sum + item.price * item.quantity;
      }, 0);
    },

    // 过滤和排序
    sortedItems() {
      return [...this.items].sort((a, b) => b.price - a.price);
    },
  },
};

// Composition API
import { ref, computed } from "vue";

const firstName = ref("Tom");
const lastName = ref("Jerry");

// 只读
const fullName = computed(() => `${firstName.value} ${lastName.value}`);

// 可读可写
const fullName = computed({
  get: () => `${firstName.value} ${lastName.value}`,
  set: (newValue) => {
    const [first, last] = newValue.split(" ");
    firstName.value = first;
    lastName.value = last;
  },
});
```

**watch 详解：**

```javascript
// Options API
export default {
  data() {
    return {
      question: "",
      answer: "",
      userId: 1,
      user: null,
    };
  },

  watch: {
    // 简单监听
    question(newVal, oldVal) {
      this.answer = "Waiting for you to stop typing...";
    },

    // 立即执行
    question: {
      handler(newVal) {
        this.debouncedGetAnswer();
      },
      immediate: true, // 初始化时立即执行一次
    },

    // 深度监听
    user: {
      handler(newVal) {
        console.log("User changed:", newVal);
      },
      deep: true, // 监听对象内部变化
    },

    // 监听特定属性
    "user.name"(newVal) {
      console.log("User name changed:", newVal);
    },

    // 监听多个数据源（Vue 3）
    "userId, question"() {
      this.fetchData();
    },
  },
};

// Composition API
import { ref, watch, watchEffect } from "vue";

const question = ref("");
const answer = ref("");
const user = ref({ name: "Tom", age: 25 });

// 基础 watch
watch(question, (newVal, oldVal) => {
  answer.value = "Waiting...";
});

// 多个数据源
watch([question, answer], ([newQ, newA], [oldQ, oldA]) => {
  console.log("Question or answer changed");
});

// 深度监听
watch(
  user,
  (newVal) => {
    console.log("User changed:", newVal);
  },
  { deep: true },
);

// 立即执行
watch(
  question,
  (newVal) => {
    console.log("Question:", newVal);
  },
  { immediate: true },
);

// watchEffect - 自动追踪依赖
watchEffect(() => {
  // 自动追踪 question 作为依赖
  console.log("Question is:", question.value);
});

// watchEffect 清理
watchEffect((onCleanup) => {
  const timer = setTimeout(() => {
    console.log(question.value);
  }, 1000);

  onCleanup(() => {
    clearTimeout(timer);
  });
});
```

**使用场景对比：**

**computed 场景：**

```javascript
// ✅ 从现有数据派生新数据
const fullName = computed(() => `${firstName.value} ${lastName.value}`);

// ✅ 复杂计算缓存
const filteredList = computed(() => {
  return list.value
    .filter((item) => item.active)
    .sort((a, b) => b.score - a.score);
});

// ✅ 表单验证状态
const isValid = computed(() => {
  return email.value.includes("@") && password.value.length >= 6;
});

// ✅ 计算类名/样式
const classObject = computed(() => ({
  active: isActive.value,
  "text-danger": hasError.value,
}));
```

**watch 场景：**

```javascript
// ✅ 异步操作
watch(searchQuery, async (newQuery) => {
  if (newQuery.length > 2) {
    results.value = await searchAPI(newQuery);
  }
});

// ✅ 复杂逻辑
watch(
  cart,
  () => {
    saveToLocalStorage(cart.value);
    updateCartBadge();
    recalculateShipping();
  },
  { deep: true },
);

// ✅ 监听路由变化
watch(
  () => route.params.id,
  (newId) => {
    fetchUser(newId);
  },
);

// ✅ 监听 props 变化
watch(
  () => props.userId,
  (newId, oldId) => {
    if (newId !== oldId) {
      loadUserData(newId);
    }
  },
);
```

**常见错误：**

```javascript
// ❌ 在 computed 中执行异步操作
const data = computed(async () => {
  return await fetchData(); // 错误！返回的是 Promise
});

// ✅ 应该使用 watch
const data = ref(null);
watch(someValue, async () => {
  data.value = await fetchData();
});

// ❌ 在 computed 中修改其他状态
const badComputed = computed(() => {
  otherValue.value = 123; // 副作用！
  return someValue.value * 2;
});

// ❌ 过度使用 watch 做简单计算
watch([firstName, lastName], ([f, l]) => {
  fullName.value = `${f} ${l}`; // 应该用 computed
});
```

**最佳实践：**

```javascript
// 1. 优先使用 computed，它更简单且有缓存
const displayName = computed(() => {
  return user.value?.name || "Anonymous";
});

// 2. watch 用于需要执行副作用的场景
watch(route, () => {
  analytics.trackPageView(route.path);
});

// 3. 使用 watchEffect 简化监听多个依赖
watchEffect(() => {
  // 自动追踪所有用到的响应式数据
  console.log(user.value.name, user.value.age);
});

// 4. 记得清理副作用
watch(id, (newId, oldId, onCleanup) => {
  const controller = new AbortController();
  fetchUser(newId, { signal: controller.signal });

  onCleanup(() => {
    controller.abort();
  });
});
```

Vue 性能优化涉及多个层面，从代码编写到构建部署都有优化空间。

**一、代码层面优化**

**1. v-if vs v-show 的选择**

```vue
<!-- 频繁切换用 v-show（ display 切换）-->
<modal v-show="isOpen" />

<!-- 条件较少变化用 v-if（DOM 创建/销毁）-->
<admin-panel v-if="isAdmin" />
```

**2. v-for 与 v-if 不要同时使用**

```vue
<!-- ❌ 低效：每次渲染都遍历整个列表 -->
<div v-for="item in list" v-if="item.active" :key="item.id">
  {{ item.name }}
</div>

<!-- ✅ 高效：先过滤再渲染 -->
<div v-for="item in activeItems" :key="item.id">
  {{ item.name }}
</div>

<script>
computed: {
  activeItems() {
    return this.list.filter(item => item.active);
  }
}
</script>

<!-- ✅ 或者用 template -->
<template v-for="item in list" :key="item.id">
  <div v-if="item.active">{{ item.name }}</div>
</template>
```

**3. 合理使用 key**

```vue
<!-- 避免使用 index 作为 key -->
<div v-for="item in list" :key="item.id">  <!-- ✅ -->
<div v-for="(item, index) in list" :key="index">  <!-- ❌ 可能有问题 -->
```

**4. 计算属性缓存**

```javascript
// ✅ computed 有缓存
const filteredList = computed(() => {
  return list.value.filter((item) => item.score > 80);
});

// ❌ 每次渲染都执行
function getFilteredList() {
  return list.value.filter((item) => item.score > 80);
}
```

**二、组件优化**

**1. 函数式组件（Vue 3 无状态组件）**

```vue
<!-- 纯展示组件，无状态、无实例 -->
<template functional>
  <div class="divider">{{ props.title }}</div>
</template>
```

**2. 子组件拆分**

```vue
<!-- ❌ 大组件全部重新渲染 -->
<template>
  <div>
    <div>Static content</div>
    <div>{{ dynamicData }}</div>
  </div>
</template>

<!-- ✅ 拆分为小组件 -->
<template>
  <div>
    <StaticComponent />
    <DynamicComponent :data="dynamicData" />
  </div>
</template>
```

**3. 缓存组件 keep-alive**

```vue
<template>
  <keep-alive :include="['TabA', 'TabB']" :exclude="['TabC']" :max="10">
    <component :is="currentTab" />
  </keep-alive>
</template>

<script>
// 组件内部使用 activated/deactivated 生命周期
export default {
  name: "TabA",
  activated() {
    // 组件激活时刷新数据
    this.fetchData();
  },
  deactivated() {
    // 组件停用时清理
  },
};
</script>
```

**4. 异步组件（代码分割）**

```javascript
// Vue 3
import { defineAsyncComponent } from "vue";

const AsyncComp = defineAsyncComponent(
  () => import("./components/HeavyComponent.vue"),
);

// 带加载状态
const AsyncComp = defineAsyncComponent({
  loader: () => import("./HeavyComponent.vue"),
  loadingComponent: LoadingComponent,
  errorComponent: ErrorComponent,
  delay: 200,
  timeout: 3000,
});
```

**三、响应式优化**

**1. 大数据处理**

```javascript
// ❌ 大量数据直接放入响应式系统
const hugeList = ref([...10000 items]);  // 内存占用高

// ✅ 使用 Object.freeze 或 shallowRef
import { shallowRef } from 'vue';

const hugeList = shallowRef([...10000 items]);  // 不深层响应

// 或使用 Object.freeze
const staticData = Object.freeze(largeData);
```

**2. 减少 watcher**

```javascript
// ❌ 监听整个对象
watch(
  user,
  () => {
    /* ... */
  },
  { deep: true },
);

// ✅ 只监听需要的属性
watch(
  () => user.value.name,
  () => {
    /* ... */
  },
);

// ❌ 多个 watch
watch(a, () => update());
watch(b, () => update());
watch(c, () => update());

// ✅ 合并为一个 watchEffect
watchEffect(() => {
  // a, b, c 的变化都会触发，但只执行一次
  update(a.value, b.value, c.value);
});
```

**四、虚拟列表（大数据渲染）**

```vue
<template>
  <RecycleScroller
    class="scroller"
    :items="list"
    :item-size="50"
    key-field="id"
    v-slot="{ item }"
  >
    <div class="item">{{ item.name }}</div>
  </RecycleScroller>
</template>

